const rows = $input.all().map(r => r.json);

// Group by project
const byProject = {};
for (const r of rows) {
  if (!byProject[r.project_id]) {
    byProject[r.project_id] = {
      project_id: r.project_id,
      project_number: r.project_number,
      project_name: r.project_name,
      phases: []
    };
  }
  byProject[r.project_id].phases.push({
    trade: r.trade,
    days_until: Number(r.days_until),
    start_date: r.start_date,
    unordered_count: Number(r.unordered_count),
    unordered_value: Number(r.unordered_value)
  });
}

const projects = Object.values(byProject);
let lines = [];
lines.push('⏰ <b>Material-Erinnerung</b>');
lines.push('');

for (const proj of projects) {
  lines.push(`<b>${proj.project_number}</b> – ${proj.project_name}`);
  for (const phase of proj.phases) {
    const urgency = phase.days_until <= 2 ? '🔴' : phase.days_until <= 3 ? '🟡' : '🟢';
    const dateStr = new Date(phase.start_date).toLocaleDateString('de-DE');
    lines.push(`${urgency} <b>${phase.trade}</b> startet in ${phase.days_until} Tagen (${dateStr})`);
    lines.push(`   ${phase.unordered_count} Materialien nicht bestellt (~€${phase.unordered_value.toFixed(0)})`);
  }

  const orderUrl = `https://n8n.srv1045913.hstgr.cloud/webhook/m4-07-order-approve?project_id=${proj.project_id}&action=approve`;
  lines.push(`   → <a href="${orderUrl}">Jetzt bestellen</a>`);
  lines.push('');
}

return [{ json: { text: lines.join('\n'), projectCount: projects.length } }];

